import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.BbQrW5_t.js";const u=JSON.parse('{"title":"第三章 教师职业道德规范","description":"","frontmatter":{"title":"第三章 教师职业道德规范","date":"2026-07-06T00:00:00.000Z","tags":["教师资格考试","综合素质","教师职业道德"]},"headers":[],"relativePath":"study/teacher-cert/comprehensive-quality/chapter3.md","filePath":"study/teacher-cert/comprehensive-quality/chapter3.md","lastUpdated":1783652711000}'),o={name:"study/teacher-cert/comprehensive-quality/chapter3.md"};function n(l,t,h,s,i,p){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="第三章-教师职业道德规范" tabindex="-1">第三章 教师职业道德规范 <a class="header-anchor" href="#第三章-教师职业道德规范" aria-label="Permalink to &quot;第三章 教师职业道德规范&quot;">​</a></h1><blockquote><p>本章考情：必考 1 道材料分析题（14 分）+ 3-4 道选择题（6-8 分），共约 20 分 核心口诀：<strong>三爱两人一终身</strong></p></blockquote><hr><h2 id="_3-1-《中小学教师职业道德规范》-2008-年修订" tabindex="-1">3.1 《中小学教师职业道德规范》（2008 年修订） <a class="header-anchor" href="#_3-1-《中小学教师职业道德规范》-2008-年修订" aria-label="Permalink to &quot;3.1 《中小学教师职业道德规范》（2008 年修订）&quot;">​</a></h2><h3 id="一、爱国守法" tabindex="-1">一、爱国守法 <a class="header-anchor" href="#一、爱国守法" aria-label="Permalink to &quot;一、爱国守法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>完整表述</td><td>热爱祖国，热爱人民，拥护中国共产党领导，拥护社会主义。全面贯彻国家教育方针，自觉遵守教育法律法规，依法履行教师职责权利。不得有违背党和国家方针政策的言行。</td></tr><tr><td>地位</td><td>底线要求</td></tr><tr><td>具体要求</td><td>① 拥护党的领导 ② 贯彻教育方针 ③ 遵守法律法规 ④ 不得有违背方针政策的言行</td></tr><tr><td>违反情形</td><td>课堂上发表不当政治言论；体罚学生（违法）；乱收费（违法）</td></tr><tr><td>判断关键词</td><td>遵纪守法、依法执教、贯彻方针</td></tr></tbody></table><p><strong>选择题易错点</strong>：爱国守法是&quot;底线&quot;而非&quot;最高要求&quot;，教师职业道德的最高境界是&quot;为人师表&quot;</p><h3 id="二、爱岗敬业-🔴🔴" tabindex="-1">二、爱岗敬业 🔴🔴 <a class="header-anchor" href="#二、爱岗敬业-🔴🔴" aria-label="Permalink to &quot;二、爱岗敬业 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>完整表述</td><td>忠诚于人民教育事业，志存高远，勤恳敬业，甘为人梯，乐于奉献。对工作高度负责，认真备课上课，认真批改作业，认真辅导学生。不得敷衍塞责。</td></tr><tr><td>地位</td><td>本质要求</td></tr><tr><td>具体要求</td><td>① 忠诚教育事业 ② 勤恳敬业 ③ 认真备课上课 ④ 认真批改作业 ⑤ 认真辅导学生</td></tr><tr><td>高度敬业 vs 敷衍了事</td><td>认真备课 vs 不备课就上课；认真批改 vs 不批改；辅导学生 vs 放任不管</td></tr><tr><td>判断关键词</td><td>认真负责、勤恳、敬业、甘为人梯、乐于奉献、不敷衍</td></tr></tbody></table><p><strong>材料分析判断</strong>：</p><ul><li>✅ 教师课后耐心辅导学困生 → 爱岗敬业</li><li>✅ 教师精心备课到深夜 → 爱岗敬业</li><li>❌ 教师上课照本宣科 → 违背爱岗敬业</li></ul><p><strong>选择题易错点</strong>：爱岗敬业 = 本质要求（非核心、灵魂）</p><h3 id="三、关爱学生-🔴🔴🔴" tabindex="-1">三、关爱学生 🔴🔴🔴 <a class="header-anchor" href="#三、关爱学生-🔴🔴🔴" aria-label="Permalink to &quot;三、关爱学生 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>完整表述</td><td>关心爱护全体学生，尊重学生人格，平等公正对待学生。对学生严慈相济，做学生良师益友。保护学生安全，关心学生健康，维护学生权益。不讽刺、挖苦、歧视学生，不体罚或变相体罚学生。</td></tr><tr><td>地位</td><td>核心、灵魂 🔴🔴</td></tr><tr><td>具体要求</td><td>① 关心爱护全体学生 ② 尊重学生人格 ③ 平等公正对待 ④ 严慈相济 ⑤ 保护安全健康 ⑥ 不讽刺挖苦歧视 ⑦ 不体罚变相体罚</td></tr></tbody></table><p><strong>关爱 vs 溺爱辨析</strong>：</p><table tabindex="0"><thead><tr><th>维度</th><th>关爱学生</th><th>溺爱学生</th></tr></thead><tbody><tr><td>对待错误</td><td>严格要求+耐心引导</td><td>放任不管</td></tr><tr><td>对待全体</td><td>平等公正</td><td>偏爱优生</td></tr><tr><td>对待方式</td><td>严慈相济</td><td>只慈不严</td></tr><tr><td>结果</td><td>促进学生发展</td><td>不利于学生成长</td></tr></tbody></table><p><strong>判断关键词</strong>：关心爱护、尊重人格、平等公正、严慈相济、不体罚</p><p><strong>材料分析判断</strong>：</p><ul><li>✅ 教师平等对待每个学生 → 关爱学生</li><li>✅ 教师对学生严格要求但尊重人格 → 关爱学生（严慈相济）</li><li>❌ 教师体罚学生 → 违背关爱学生</li><li>❌ 教师只关注优生忽视差生 → 违背关爱学生</li></ul><p><strong>选择题易错点</strong>：关爱学生 = 核心/灵魂（考频最高的定位词）</p><h3 id="四、教书育人" tabindex="-1">四、教书育人 <a class="header-anchor" href="#四、教书育人" aria-label="Permalink to &quot;四、教书育人&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>完整表述</td><td>遵循教育规律，实施素质教育。循循善诱，诲人不倦，因材施教。培养学生良好品行，激发学生创新精神，促进学生全面发展。不以分数作为评价学生的唯一标准。</td></tr><tr><td>地位</td><td>天职、使命</td></tr><tr><td>具体要求</td><td>① 遵循教育规律 ② 实施素质教育 ③ 循循善诱 ④ 因材施教 ⑤ 培养良好品行 ⑥ 不以分数为唯一标准</td></tr></tbody></table><p><strong>素质教育 vs 应试教育的&quot;教书育人&quot;区别</strong>：</p><table tabindex="0"><thead><tr><th>维度</th><th>应试教育的教书育人</th><th>素质教育的教书育人</th></tr></thead><tbody><tr><td>目标</td><td>追求分数</td><td>全面发展</td></tr><tr><td>方法</td><td>题海战术</td><td>循循善诱、因材施教</td></tr><tr><td>评价</td><td>分数唯一</td><td>多元评价</td></tr><tr><td>内容</td><td>考什么教什么</td><td>德智体美劳</td></tr></tbody></table><p><strong>判断关键词</strong>：循循善诱、因材施教、不以分数为唯一标准</p><p><strong>选择题易错点</strong>：&quot;不以分数为唯一标准&quot;≠ 不看分数，是综合评价</p><h3 id="五、为人师表" tabindex="-1">五、为人师表 <a class="header-anchor" href="#五、为人师表" aria-label="Permalink to &quot;五、为人师表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>完整表述</td><td>坚守高尚情操，知荣明耻，严于律己，以身作则。衣着得体，语言规范，举止文明。关心集体，团结协作，尊重同事，尊重家长。作风正派，廉洁奉公。自觉抵制有偿家教，不利用职务之便谋取私利。</td></tr><tr><td>地位</td><td>内在要求</td></tr><tr><td>具体要求</td><td>① 以身作则 ② 衣着得体、语言规范、举止文明 ③ 尊重同事和家长 ④ 廉洁奉公 ⑤ 抵制有偿家教 🔴 ⑥ 不谋取私利</td></tr></tbody></table><p><strong>廉洁从教的具体规定</strong>：</p><ul><li>✅ 不得进行有偿家教 🔴🔴</li><li>✅ 不得利用职务之便谋取私利</li><li>✅ 不得收受家长礼品</li></ul><p><strong>判断关键词</strong>：以身作则、廉洁从教、抵制有偿家教、尊重同事家长</p><p><strong>选择题易错点</strong>：有偿家教 → 违背&quot;为人师表&quot;（非&quot;爱岗敬业&quot;）</p><h3 id="六、终身学习-🔴🔴" tabindex="-1">六、终身学习 🔴🔴 <a class="header-anchor" href="#六、终身学习-🔴🔴" aria-label="Permalink to &quot;六、终身学习 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>完整表述</td><td>崇尚科学精神，树立终身学习理念，拓宽知识视野，更新知识结构。潜心钻研业务，勇于探索创新，不断提高专业素养和教育教学水平。</td></tr><tr><td>地位</td><td>不竭动力</td></tr><tr><td>具体要求</td><td>① 树立终身学习理念 ② 拓宽知识视野 ③ 更新知识结构 ④ 潜心钻研 ⑤ 勇于创新</td></tr><tr><td>终身学习的途径</td><td>① 参加培训进修 ② 阅读专业书籍 ③ 同伴互助交流 ④ 网络研修 ⑤ 教学反思</td></tr></tbody></table><p><strong>判断关键词</strong>：不断学习、更新知识、进修培训、钻研创新</p><p><strong>选择题易错点</strong>：终身学习 = 不竭动力（非&quot;基本要求&quot;）</p><h3 id="六条规范定位速查-🔴🔴" tabindex="-1">六条规范定位速查 🔴🔴 <a class="header-anchor" href="#六条规范定位速查-🔴🔴" aria-label="Permalink to &quot;六条规范定位速查 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条目</th><th>地位/关键词</th></tr></thead><tbody><tr><td>爱国守法</td><td>底线要求</td></tr><tr><td>爱岗敬业</td><td>本质要求</td></tr><tr><td>关爱学生</td><td>核心、灵魂</td></tr><tr><td>教书育人</td><td>天职、使命</td></tr><tr><td>为人师表</td><td>内在要求</td></tr><tr><td>终身学习</td><td>不竭动力</td></tr></tbody></table><hr><h2 id="_3-2-《中小学班主任工作条例》" tabindex="-1">3.2 《中小学班主任工作条例》 <a class="header-anchor" href="#_3-2-《中小学班主任工作条例》" aria-label="Permalink to &quot;3.2 《中小学班主任工作条例》&quot;">​</a></h2><h3 id="核心内容" tabindex="-1">核心内容 <a class="header-anchor" href="#核心内容" aria-label="Permalink to &quot;核心内容&quot;">​</a></h3><ol><li><strong>班主任的地位</strong>：班级工作的组织者、领导者和教育者</li><li><strong>班主任的角色</strong>：学生的人生导师 🔴</li><li><strong>班主任的配备</strong>：每个班级应配备一名班主任</li><li><strong>班主任的选聘</strong>：从班级任课教师中选聘</li><li><strong>班主任津贴</strong>：纳入绩效工资管理</li></ol><h3 id="班主任的职责与任务" tabindex="-1">班主任的职责与任务 <a class="header-anchor" href="#班主任的职责与任务" aria-label="Permalink to &quot;班主任的职责与任务&quot;">​</a></h3><table tabindex="0"><thead><tr><th>职责</th><th>具体内容</th></tr></thead><tbody><tr><td>全面了解学生</td><td>思想品德、学习情况、身心健康、家庭情况</td></tr><tr><td>班级日常管理</td><td>班规制定、班干部培养、班级文化建设</td></tr><tr><td>组织班级活动</td><td>班会、文体活动、社会实践活动</td></tr><tr><td>协调各方教育力量</td><td>与任课教师沟通、家校联系</td></tr><tr><td>做好学生评价</td><td>操行评定、综合素质评价</td></tr></tbody></table><h3 id="班主任的权利" tabindex="-1">班主任的权利 <a class="header-anchor" href="#班主任的权利" aria-label="Permalink to &quot;班主任的权利&quot;">​</a></h3><ol><li>有权参与学校管理</li><li>有权对学生的教育管理做出决定</li><li>有权获得适当津贴</li><li>有权拒绝不合理的工作安排</li></ol><h3 id="选择题高频考点" tabindex="-1">选择题高频考点 <a class="header-anchor" href="#选择题高频考点" aria-label="Permalink to &quot;选择题高频考点&quot;">​</a></h3><ol><li>班主任 = 班级工作的组织者、领导者、教育者</li><li>班主任 = 学生的人生导师</li><li>班主任从任课教师中选聘（非专门岗位）</li><li>操行评定由班主任负责</li></ol><hr><h2 id="_3-3-教师职业行为准则-新时代" tabindex="-1">3.3 教师职业行为准则（新时代） <a class="header-anchor" href="#_3-3-教师职业行为准则-新时代" aria-label="Permalink to &quot;3.3 教师职业行为准则（新时代）&quot;">​</a></h2><h3 id="十条准则" tabindex="-1">十条准则 <a class="header-anchor" href="#十条准则" aria-label="Permalink to &quot;十条准则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>准则</th><th>核心要求</th></tr></thead><tbody><tr><td>1</td><td>坚定政治方向</td><td>坚持正确政治方向</td></tr><tr><td>2</td><td>自觉爱国守法</td><td>遵纪守法</td></tr><tr><td>3</td><td>传播优秀文化</td><td>弘扬正能量</td></tr><tr><td>4</td><td>潜心教书育人</td><td>落实立德树人</td></tr><tr><td>5</td><td>关心爱护学生</td><td>严慈相济</td></tr><tr><td>6</td><td>加强安全防范</td><td>保护学生安全</td></tr><tr><td>7</td><td>坚持言行雅正</td><td>为人师表</td></tr><tr><td>8</td><td>秉持公平诚信</td><td>公正评价</td></tr><tr><td>9</td><td>坚守廉洁自律</td><td>不谋私利</td></tr><tr><td>10</td><td>规范从教行为</td><td>不违规补课</td></tr></tbody></table><h3 id="与职业道德规范的对应" tabindex="-1">与职业道德规范的对应 <a class="header-anchor" href="#与职业道德规范的对应" aria-label="Permalink to &quot;与职业道德规范的对应&quot;">​</a></h3><table tabindex="0"><thead><tr><th>职业道德规范</th><th>对应的行为准则</th></tr></thead><tbody><tr><td>爱国守法</td><td>坚定政治方向 + 自觉爱国守法</td></tr><tr><td>爱岗敬业</td><td>潜心教书育人</td></tr><tr><td>关爱学生</td><td>关心爱护学生 + 加强安全防范</td></tr><tr><td>教书育人</td><td>传播优秀文化 + 潜心教书育人</td></tr><tr><td>为人师表</td><td>坚持言行雅正 + 秉持公平诚信 + 坚守廉洁自律 + 规范从教行为</td></tr><tr><td>终身学习</td><td>潜心教书育人（持续提升）</td></tr></tbody></table><hr><h2 id="_3-4-材料分析题专题" tabindex="-1">3.4 材料分析题专题 <a class="header-anchor" href="#_3-4-材料分析题专题" aria-label="Permalink to &quot;3.4 材料分析题专题&quot;">​</a></h2><h3 id="答题模板" tabindex="-1">答题模板 <a class="header-anchor" href="#答题模板" aria-label="Permalink to &quot;答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>该老师的行为符合/违背了教师职业道德规范的要求，具体分析如下：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第一，该老师的行为符合/违背了&quot;……&quot;的要求。</span></span>
<span class="line"><span>   教师职业道德规范规定，……（阐述规范内容）。</span></span>
<span class="line"><span>   材料中，该老师……（结合材料），</span></span>
<span class="line"><span>   这体现了/违背了……（回扣规范）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二，……</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三，……</span></span>
<span class="line"><span></span></span>
<span class="line"><span>综上所述，该老师的行为值得学习/需要改进。</span></span></code></pre></div><h3 id="真题示例-1-关爱学生" tabindex="-1">真题示例 1：关爱学生 <a class="header-anchor" href="#真题示例-1-关爱学生" aria-label="Permalink to &quot;真题示例 1：关爱学生&quot;">​</a></h3><p><strong>材料</strong>：陈老师在课堂上发现学生小王在玩手机。陈老师没有当众没收手机并批评小王，而是走到小王身边轻轻拍了拍他的肩膀，示意他收起手机。课后，陈老师找小王谈话，了解到小王因为父母离婚心情不好，用手机和远在外地的妈妈聊天。陈老师表示理解，同时引导小王在课余时间和妈妈联系。之后，小王上课不再玩手机，学习也更加认真了。</p><p><strong>问题</strong>：请从教师职业道德的角度，评析陈老师的行为。</p><p><strong>参考答案</strong>：</p><p>陈老师的行为是恰当的，符合教师职业道德规范的要求，具体分析如下：</p><p>第一，陈老师的行为符合&quot;关爱学生&quot;的要求。关爱学生要求教师关心爱护全体学生，尊重学生人格，严慈相济。材料中，陈老师没有当众批评小王，而是课后私下谈话，了解了小王玩手机的真实原因并表示理解，体现了尊重学生人格、关心学生心理。</p><p>第二，陈老师的行为符合&quot;教书育人&quot;的要求。教书育人要求教师循循善诱，因材施教，不以分数为唯一标准。材料中，陈老师不是简单禁止手机使用，而是引导小王在课余时间联系妈妈，循循善诱地解决了问题。</p><p>第三，陈老师的行为符合&quot;为人师表&quot;的要求。为人师表要求教师严于律己，以身作则。材料中，陈老师处理问题的方式温和而有分寸，体现了良好的师德风范。</p><p>综上所述，陈老师的行为值得学习。</p><h3 id="真题示例-2-爱岗敬业-终身学习" tabindex="-1">真题示例 2：爱岗敬业 + 终身学习 <a class="header-anchor" href="#真题示例-2-爱岗敬业-终身学习" aria-label="Permalink to &quot;真题示例 2：爱岗敬业 + 终身学习&quot;">​</a></h3><p><strong>材料</strong>：赵老师是一名乡村中学的数学教师，虽然条件艰苦，但她始终坚守岗位，认真对待每一节课。她发现传统的教学方法效果不好，就利用业余时间学习新的教学理念，参加网上研修课程。她将翻转课堂引入教学，取得了很好的效果。暑假期间，她还自费参加了省级骨干教师培训。有人劝她调到城里条件好的学校，她说：&quot;这里的孩子更需要好老师。&quot;</p><p><strong>问题</strong>：请从教师职业道德的角度，评析赵老师的行为。</p><p><strong>参考答案</strong>：</p><p>赵老师的行为是恰当的，符合教师职业道德规范的要求，具体分析如下：</p><p>第一，赵老师的行为符合&quot;爱岗敬业&quot;的要求。爱岗敬业要求教师忠诚于人民教育事业，勤恳敬业，甘为人梯。材料中，赵老师在条件艰苦的乡村坚守岗位，面对调离机会选择留下，说&quot;这里的孩子更需要好老师&quot;，体现了忠诚教育事业、勤恳敬业、甘为人梯的精神。</p><p>第二，赵老师的行为符合&quot;终身学习&quot;的要求。终身学习要求教师拓宽知识视野，更新知识结构，不断提高专业素养。材料中，赵老师利用业余时间学习新理念、参加网上研修、自费参加培训，体现了终身学习的精神。</p><p>第三，赵老师的行为符合&quot;关爱学生&quot;的要求。关爱学生要求教师关心爱护全体学生。材料中，赵老师发现教学方法不好就主动改进，为了学生的发展不断提升自己，体现了对学生成长的关心。</p><p>综上所述，赵老师的行为值得学习。</p><h3 id="真题示例-3-为人师表-教书育人" tabindex="-1">真题示例 3：为人师表 + 教书育人 <a class="header-anchor" href="#真题示例-3-为人师表-教书育人" aria-label="Permalink to &quot;真题示例 3：为人师表 + 教书育人&quot;">​</a></h3><p><strong>材料</strong>：李老师是某中学的班主任。期中考试后，有家长提出要给李老师送礼，希望李老师能安排自己孩子坐前排。李老师婉言谢绝了礼物，并解释说座位是按照身高和视力合理安排的，会公平对待每一个学生。有同事建议李老师办课外辅导班增加收入，李老师也拒绝了，说：&quot;我要把精力放在课堂教学上，让每个学生都在课堂上学会。&quot;</p><p><strong>问题</strong>：请从教师职业道德的角度，评析李老师的行为。</p><p><strong>参考答案</strong>：</p><p>李老师的行为是恰当的，符合教师职业道德规范的要求，具体分析如下：</p><p>第一，李老师的行为符合&quot;为人师表&quot;的要求。为人师表要求教师廉洁奉公，自觉抵制有偿家教，不利用职务之便谋取私利。材料中，李老师拒绝了家长的礼物和同事办辅导班的建议，体现了廉洁从教、不以权谋私。</p><p>第二，李老师的行为符合&quot;关爱学生&quot;的要求。关爱学生要求教师平等公正对待学生。材料中，李老师按身高和视力安排座位，公平对待每个学生，体现了平等公正。</p><p>第三，李老师的行为符合&quot;教书育人&quot;的要求。教书育人要求教师潜心教学，不以分数为唯一标准。材料中，李老师把精力放在课堂教学上，让每个学生都在课堂上学会，体现了潜心教书育人。</p><p>综上所述，李老师的行为值得学习。</p><h3 id="常见失分点" tabindex="-1">常见失分点 <a class="header-anchor" href="#常见失分点" aria-label="Permalink to &quot;常见失分点&quot;">​</a></h3><ol><li>❌ 把&quot;有偿家教&quot;归到&quot;爱岗敬业&quot; → ✅ 归到&quot;为人师表&quot;</li><li>❌ 只写条目名称不展开内容 → 扣理论分</li><li>❌ 材料和理论脱节，没有逻辑衔接 → 扣分析分</li><li>❌ 混淆&quot;核心/灵魂&quot;（关爱学生）与&quot;本质要求&quot;（爱岗敬业）</li></ol><hr><h2 id="_3-5-知识速记卡" tabindex="-1">3.5 知识速记卡 <a class="header-anchor" href="#_3-5-知识速记卡" aria-label="Permalink to &quot;3.5 知识速记卡&quot;">​</a></h2><h3 id="口诀" tabindex="-1">口诀 <a class="header-anchor" href="#口诀" aria-label="Permalink to &quot;口诀&quot;">​</a></h3><p><strong>三爱两人一终身</strong>：爱国守法、爱岗敬业、关爱学生、教书育人、为人师表、终身学习</p><h3 id="六条规范关键词速查" tabindex="-1">六条规范关键词速查 <a class="header-anchor" href="#六条规范关键词速查" aria-label="Permalink to &quot;六条规范关键词速查&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条目</th><th>一句话记忆</th><th>地位</th></tr></thead><tbody><tr><td>爱国守法</td><td>不违法</td><td>底线</td></tr><tr><td>爱岗敬业</td><td>不敷衍</td><td>本质</td></tr><tr><td>关爱学生</td><td>不体罚</td><td>核心/灵魂</td></tr><tr><td>教书育人</td><td>不唯分数</td><td>天职</td></tr><tr><td>为人师表</td><td>不有偿家教</td><td>内在</td></tr><tr><td>终身学习</td><td>不停止学习</td><td>不竭动力</td></tr></tbody></table><h3 id="易混淆点辨析" tabindex="-1">易混淆点辨析 <a class="header-anchor" href="#易混淆点辨析" aria-label="Permalink to &quot;易混淆点辨析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>混淆点</th><th>区别</th></tr></thead><tbody><tr><td>关爱学生 vs 为人师表</td><td>关爱学生 = 对学生好；为人师表 = 自己做得好</td></tr><tr><td>爱岗敬业 vs 终身学习</td><td>爱岗敬业 = 认真工作；终身学习 = 持续提升</td></tr><tr><td>有偿家教归哪条？</td><td>为人师表（廉洁从教），不是爱岗敬业</td></tr><tr><td>收受礼品归哪条？</td><td>为人师表（不谋私利），不是关爱学生</td></tr><tr><td>体罚学生归哪条？</td><td>关爱学生（不体罚变相体罚），不是爱国守法</td></tr><tr><td>不以分数为唯一标准？</td><td>教书育人，不是关爱学生</td></tr></tbody></table>`,95)])])}const q=d(o,[["render",n]]);export{u as __pageData,q as default};
